const items = $input.all();

const noticias = items.map((item, index) => {
  const titulo = item.json.titulo || '';
  const snippet = (item.json.descricao || '')
    .replace(/<[^>]*>/g, '')
    .slice(0, 150);
  const link = item.json.link || '';
  const dominio = item.json.dominio || '';
  const data = item.json.data || '';
  const flag = item.json.tipo === 'antigo' ? ' [+1mês]' : '';
  return `${index + 1}. [${dominio}${flag}] ${titulo} | ${snippet} | ${link} | ${data}`;
}).join('\n');

return [{
  json: {
    noticias_consolidadas: noticias,
    total: items.length,
    dominios: [...new Set(items.map(i => i.json.dominio))].join(', ')
  }
}];

const texto = $json.text || '';
const clean = texto.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let dados;
try {
  dados = JSON.parse(clean);
} catch(e) {
  return [{
    json: {
      resumo: texto.slice(0, 1000),
      tendencias: '',
      oportunidades: '',
      analytics: '{}',
      periodo: new Date().toISOString()
    }
  }];
}

const sanitize = (str) => (str || '')
  .replace(/\r/g, ' ')
  .replace(/"/g, "'")
  .replace(/\\/g, '')
  .trim();

return [{
  json: {
    resumo: sanitize(dados.relatorio?.resumo),
    tendencias: sanitize(dados.relatorio?.tendencias),
    oportunidades: sanitize(dados.relatorio?.oportunidades),
    analytics: JSON.stringify(dados.analytics || {}),
    periodo: new Date().toISOString()
  }
}];

const items = $input.all();

const dominiosRuins = ['techncruncher', 'blogger.com', 'soundpeats'];

const limitePorDominio = {
  'news.ycombinator.com': 2,
  'news.google.com': 0,
  'bdtechtalks.com': 3,
};

const agora = new Date();
const umMesAtras = new Date(agora.getTime() - 30 * 24 * 60 * 60 * 1000);

const filtrados = items
  .filter(item => item.json.title && item.json.isoDate)
  .filter(item => {
    const link = (item.json.link || '').toLowerCase();
    return !dominiosRuins.some(d => link.includes(d));
  })
  .filter(item => {
    const snippet = (item.json.contentSnippet || item.json.description || '').trim();
    return snippet.length > 50;
  })
  .filter(item => {
    const link = item.json.link || '';
    return !link.includes('news.google.com/rss/articles');
  });

const recentes = filtrados
  .filter(item => new Date(item.json.isoDate) >= umMesAtras)
  .sort((a, b) => new Date(b.json.isoDate) - new Date(a.json.isoDate));

const antigos = filtrados
  .filter(item => new Date(item.json.isoDate) < umMesAtras)
  .sort((a, b) => new Date(b.json.isoDate) - new Date(a.json.isoDate));

const contagem = {};
const balanceados = [];
const dominiosPresentes = new Set();

for (const item of recentes) {
  const link = item.json.link || '';
  const dominio = link.split('/')[2]?.replace('www.', '') || 'desconhecido';
  const limite = limitePorDominio.hasOwnProperty(dominio) ? limitePorDominio[dominio] : 4;
  if (limite === 0) continue;
  contagem[dominio] = (contagem[dominio] || 0) + 1;
  if (contagem[dominio] <= limite) {
    balanceados.push({ ...item, dominio, tipo: 'recente' });
    dominiosPresentes.add(dominio);
  }
  if (balanceados.length >= 18) break;
}

for (const item of antigos) {
  if (balanceados.length >= 25) break;
  const link = item.json.link || '';
  const dominio = link.split('/')[2]?.replace('www.', '') || 'desconhecido';
  const limite = limitePorDominio.hasOwnProperty(dominio) ? limitePorDominio[dominio] : 4;
  if (limite === 0) continue;
  contagem[dominio] = (contagem[dominio] || 0) + 1;
  const prioritario = !dominiosPresentes.has(dominio);
  if (prioritario || contagem[dominio] <= limite) {
    balanceados.push({ ...item, dominio, tipo: 'antigo' });
    dominiosPresentes.add(dominio);
  }
}

return balanceados.map(item => ({
  json: {
    titulo: item.json.title || '',
    link: item.json.link || '',
    descricao: item.json.contentSnippet || item.json.description || '',
    dominio: item.dominio,
    data: item.json.isoDate?.slice(0, 10) || '',
    tipo: item.tipo
  }
}));

const texto = $json.text || '';
const clean = texto.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let dados;
try {
  dados = JSON.parse(clean);
} catch(e) {
  return [{ json: { fatos_extraidos: texto, erro: true } }];
}

// Formata os fatos extraídos de forma compacta para o Call 2
const fatosFormatados = dados.noticias.map((n, i) => {
  const fatos = n.fatos.join(' | ');
  const techs = n.tecnologias_mencionadas.length > 0 
    ? ` [Techs: ${n.tecnologias_mencionadas.join(', ')}]` 
    : '';
  return `${i+1}. [${n.fonte}] [${n.setor}] ${n.titulo}\nData: ${n.data} | URL: ${n.url}\nFatos: ${fatos}${techs}`;
}).join('\n\n');

return [{
  json: {
    fatos_extraidos: fatosFormatados,
    noticias_raw: JSON.stringify(dados.noticias),
    total: dados.total
  }
}];

