// Função de conversão markdown para HTML
function mdToHtml(text) {
  if (!text) return '';
  let html = text
    .replace(/\\n/g, '\n')
    .replace(/\r\n/g, '\n');

  html = html.replace(/^## .+\n?/, '');

  html = html.replace(/^\*\*(\d+\..+?)\*\*$/gm,
    `<div style="font-family:Georgia,serif;font-size:16px;font-weight:700;font-style:italic;color:#f0f0f0;margin:28px 0 12px;padding-left:14px;border-left:3px solid #00CED1;line-height:1.4;">$1</div>`);

  html = html.replace(/\*\*(.*?)\*\*/g, '<strong style="color:#e0e0e0;font-weight:600;">$1</strong>');

  html = html.replace(/^(Fonte|Data|Setor|Gatilho|Proposta de valor|Modelo de negócio|Barreira principal|Potencial|Evidências|Análise|Impacto Brasil|Horizonte|Contexto técnico|Por que importa|O que aconteceu|Area|Base|Descricao):\s*(.+)$/gm,
    `<table cellpadding="0" cellspacing="0" style="margin:4px 0;"><tr><td style="font-family:'Helvetica Neue',Arial,sans-serif;font-size:9px;letter-spacing:1.5px;text-transform:uppercase;color:#00CED1;font-weight:600;white-space:nowrap;padding-right:12px;vertical-align:top;padding-top:2px;min-width:100px;">$1</td><td style="font-size:12px;color:#888;font-weight:300;line-height:1.6;">$2</td></tr></table>`);

  html = html.replace(/(https?:\/\/[^\s<"]+)/g,
    '<a href="$1" style="color:#00CED1;text-decoration:none;font-size:11px;">↗ Ver fonte</a>');

  html = html.replace(/^---+$/gm,
    '<div style="border-top:1px solid #1e1e1e;margin:28px 0;"></div>');

  const blocks = html.split(/\n{2,}/);
  html = blocks.map(block => {
    block = block.trim();
    if (!block) return '';
    if (block.startsWith('<div') || block.startsWith('<a') || block.startsWith('<table')) return block;
    const lines = block.split('\n').filter(l => l.trim());
    if (!lines.length) return '';
    return `<p style="font-size:13px;line-height:1.85;color:#888;font-weight:300;margin:8px 0;">${lines.join('<br>')}</p>`;
  }).join('\n');

  return html;
}

